-- ============================================================
-- cloud-engineer-roadmap.seed.sql
-- Detailed curated Cloud Engineer roadmap seed.
-- Re-runnable/idempotent for this roadmap title.
-- ============================================================

BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id=e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id=rv.roadmap_id WHERE r.title IN ('Cloud Engineer Roadmap', 'Cloud Engineering Roadmap', 'Cloud Engineer Roadmap - Full Detailed Seed'));
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id=e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id=rv.roadmap_id WHERE r.title IN ('Cloud Engineer Roadmap', 'Cloud Engineering Roadmap', 'Cloud Engineer Roadmap - Full Detailed Seed'));
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id=rv.roadmap_id WHERE r.title IN ('Cloud Engineer Roadmap', 'Cloud Engineering Roadmap', 'Cloud Engineer Roadmap - Full Detailed Seed'));
DELETE FROM public.roadmap WHERE title IN ('Cloud Engineer Roadmap', 'Cloud Engineering Roadmap', 'Cloud Engineer Roadmap - Full Detailed Seed');

ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, category=EXCLUDED.category, is_active=true, updated_at=now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug='cloud-engineer'), inserted_roadmap AS (
), inserted_version AS (
  SELECT roadmap_id,1,'published','Cloud Engineer Roadmap v1','A practical cloud engineering roadmap that moves from cloud foundations to secure, reliable, cost-aware, production-ready cloud architecture and operations.',405,'none','{"source":"platform-generated","reference":"roadmap.sh/aws and cloud provider docs","estimatedHoursPolicy":"representative required path"}'::jsonb,'TB','custom',now() FROM inserted_roadmap RETURNING roadmap_version_id,roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY,name text NOT NULL,category text NOT NULL,description text NOT NULL) ON COMMIT DROP;

DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY,title text NOT NULL,url text NOT NULL,resource_type text NOT NULL,description text NOT NULL,provider text,difficulty_level text) ON COMMIT DROP;
UPDATE public.learning_resource lr SET title=sr.title, resource_type=sr.resource_type, description=sr.description, provider=sr.provider, difficulty_level=sr.difficulty_level, language_code='en', verification_status='verified', updated_at=now() FROM (SELECT DISTINCT ON (url) title,url,resource_type,description,provider,difficulty_level FROM seed_resource ORDER BY url,resource_key) sr WHERE lr.url=sr.url;

DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (node_key text PRIMARY KEY,parent_key text,order_index int NOT NULL,node_type text NOT NULL,checkpoint_type text,selection_type text,required_count int,title text NOT NULL,description text NOT NULL,reason text NOT NULL,layout_role text,layout_group text,layout_rank int,layout_order int,estimated_hours int,difficulty_level text,priority int,position_x int,position_y int,metadata jsonb,is_required boolean,is_trackable boolean,learning_outcomes jsonb,completion_criteria jsonb,node_id uuid DEFAULT gen_random_uuid()) ON COMMIT DROP;

DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL,skill_slug text NOT NULL) ON COMMIT DROP;

DROP TABLE IF EXISTS seed_node_resource;
CREATE TEMP TABLE seed_node_resource (node_key text NOT NULL,resource_key text NOT NULL,order_index int NOT NULL) ON COMMIT DROP;

DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL,to_key text NOT NULL,edge_type text NOT NULL,dependency_type text NOT NULL,condition jsonb NOT NULL) ON COMMIT DROP;

COMMIT;
