INSERT INTO public.career_role (name, slug, description, category, is_active) VALUES ('Cloud Engineer', 'cloud-engineer', 'Cloud engineering path covering IAM, networking, compute, storage, serverless, containers, IaC, monitoring, security, reliability, cost optimization, migration, and portfolio-ready cloud projects.', 'Cloud and Infrastructure', true)
  INSERT INTO public.roadmap (career_role_id,title,description,roadmap_type,source_type,visibility) SELECT career_role_id,'Cloud Engineer Roadmap','A structured learning path for becoming a cloud engineer, covering cloud fundamentals, Linux, networking, IAM, compute, storage, databases, serverless, containers, infrastructure as code, monitoring, security, reliability, cost optimization, migration, multi-cloud awareness, and portfolio-ready cloud projects.','template','static','public' FROM role_row RETURNING roadmap_id
