INSERT INTO public.learning_resource (title,url,resource_type,description,provider,difficulty_level,language_code,verification_status) SELECT sr.title,sr.url,sr.resource_type,sr.description,sr.provider,sr.difficulty_level,'en','verified' FROM (SELECT DISTINCT ON (url) title,url,resource_type,description,provider,difficulty_level FROM seed_resource ORDER BY url,resource_key) sr WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url=sr.url);
