INSERT INTO public.roadmap_node_skill (roadmap_node_id,skill_id) SELECT DISTINCT rn.roadmap_node_id,s.skill_id FROM seed_node_skill sns JOIN seed_node sn ON sn.node_key=sns.node_key JOIN seed_roadmap_map m ON true JOIN public.roadmap_node rn ON rn.roadmap_version_id=m.roadmap_version_id AND rn.slug=sn.node_key JOIN public.skill s ON s.slug=sns.skill_slug ON CONFLICT (roadmap_node_id,skill_id) DO NOTHING;
