INSERT INTO public.roadmap_node_resource (roadmap_node_id,learning_resource_id,order_index,is_primary) SELECT DISTINCT ON (rn.roadmap_node_id,lr.learning_resource_id) rn.roadmap_node_id,lr.learning_resource_id,snr.order_index,snr.order_index<=3 FROM seed_node_resource snr JOIN seed_node sn ON sn.node_key=snr.node_key JOIN seed_roadmap_map m ON true JOIN public.roadmap_node rn ON rn.roadmap_version_id=m.roadmap_version_id AND rn.slug=sn.node_key JOIN seed_resource sr ON sr.resource_key=snr.resource_key JOIN public.learning_resource lr ON lr.url=sr.url ORDER BY rn.roadmap_node_id,lr.learning_resource_id,snr.order_index ON CONFLICT (roadmap_node_id,learning_resource_id) DO UPDATE SET order_index=EXCLUDED.order_index,is_primary=EXCLUDED.is_primary;
INSERT INTO public.learning_resource_skill (learning_resource_id,skill_id) SELECT DISTINCT lr.learning_resource_id,s.skill_id FROM seed_node_resource snr JOIN seed_node_skill sns ON sns.node_key=snr.node_key JOIN seed_resource sr ON sr.resource_key=snr.resource_key JOIN public.learning_resource lr ON lr.url=sr.url JOIN public.skill s ON s.slug=sns.skill_slug ON CONFLICT (learning_resource_id,skill_id) DO NOTHING;
